import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { collection, addDoc, Timestamp } from 'firebase/firestore';

function CreateTeam() {
  const { gameId } = useParams();
  const navigate = useNavigate();

  const [teamData, setTeamData] = useState({
    name: '',
    color: '#386C0B',
    playerCount: 4,
    tactic: 'Strategy 1',
    entranceSong: '',
  });

  const tactics = ['Strategy 1', 'Strategy 2', 'Strategy 3'];

  const handleChange = (e) => {
    setTeamData({ ...teamData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await addDoc(collection(db, 'teams'), {
        ...teamData,
        gameId: gameId,
        createdAt: Timestamp.now(),
      });
      alert('Team created successfully!');
      navigate('/set-game');
    } catch (error) {
      console.error('Error creating team:', error);
      alert('Failed to create team.');
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Create Team</h1>
      <form onSubmit={handleSubmit} style={styles.form}>
        <label style={styles.label}>Team Name</label>
        <input
          type="text"
          name="name"
          placeholder="Enter team name"
          value={teamData.name}
          onChange={handleChange}
          required
          style={styles.input}
        />

        <label style={styles.label}>Team Color</label>
        <input
          type="color"
          name="color"
          value={teamData.color}
          onChange={handleChange}
          style={styles.colorInput}
        />

        <label style={styles.label}>Number of Players</label>
        <select
          name="playerCount"
          value={teamData.playerCount}
          onChange={handleChange}
          style={styles.select}
        >
          <option value={4}>4 Players</option>
          <option value={5}>5 Players</option>
          <option value={6}>6 Players</option>
        </select>

        <label style={styles.label}>Select Tactic</label>
        <select
          name="tactic"
          value={teamData.tactic}
          onChange={handleChange}
          style={styles.select}
        >
          {tactics.map((tactic, index) => (
            <option key={index} value={tactic}>
              {tactic}
            </option>
          ))}
        </select>

        <label style={styles.label}>Entrance Song (YouTube Link)</label>
        <input
          type="url"
          name="entranceSong"
          placeholder="Paste YouTube link"
          value={teamData.entranceSong}
          onChange={handleChange}
          style={styles.input}
        />

        <button type="submit" style={styles.button}>Create Team</button>
        <button type="button" style={styles.cancelButton} onClick={() => navigate('/set-game')}>Cancel</button>
      </form>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
  },
  title: {
    fontSize: '24px',
    color: '#293F14',
    textShadow: '2px 2px #7FC6A4',
    marginBottom: '30px',
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
    width: '300px',
  },
  label: {
    fontSize: '14px',
    color: '#293F14',
  },
  input: {
    padding: '10px',
    borderRadius: '8px',
    border: '2px solid #7FC6A4',
    fontSize: '14px',
    textAlign: 'center',
  },
  colorInput: {
    width: '100%',
    height: '40px',
    borderRadius: '8px',
    border: '2px solid #7FC6A4',
  },
  select: {
    padding: '10px',
    borderRadius: '8px',
    border: '2px solid #7FC6A4',
    fontSize: '14px',
  },
  button: {
    backgroundColor: '#386C0B',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    border: '2px solid #5D737E',
    cursor: 'pointer',
    fontSize: '14px',
  },
  cancelButton: {
    backgroundColor: '#5D737E',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    border: '2px solid #293F14',
    cursor: 'pointer',
    fontSize: '14px',
  },
};

export default CreateTeam;
